+    var
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        NewWarehouseActivityLine: Record "Warehouse Activity Line";
+        RemQtyToPickBase: Decimal;
+        IsHandled: Boolean;
