+            until (FromBinContent.Next() = 0) or (RemQtyToPickBase = 0);
+        OnAfterInsertPickOrMoveBinWhseActLine(NewWarehouseActivityLine, CurrWarehouseActivityHeader, RemQtyToPickBase)
+    end;
