+            NewWarehouseActivityLine."No." := CurrWarehouseActivityHeader."No.";
+            WhseWorksheetLine2.TestField(WhseWorksheetLine2."Location Code");
+            GetLocation(WhseWorksheetLine2."Location Code");
+            if CurrLocation."Bin Mandatory" then
