+    local procedure GetQtyInBinNotBlockedNotDedicatedWithoutItemTrackingFilter(LocationCode: Code[20]; ItemNo: Code[20]; Variantcode: Code[20]) QtyInBinNotBlockedNotDedicatedWithoutItemTrackingFilter: Decimal
