+    procedure CheckReservedItemTrkg(CheckType: Enum "Item Tracking Type"; ItemTrkgCode: Code[50])
+    var
+        IsHandled: Boolean;
+    begin
+        IsHandled := ("Activity Type" = "Activity Type"::"Invt. Pick") and "Assemble to Order";
