+        if IsHandled then
+            exit;
+
+        case CheckType of
+            CheckType::"Serial No.":
+                CheckReservedItemTrkgForSerialNo(ItemTrkgCode);
+            CheckType::"Lot No.":
+                CheckReservedItemTrkgForLotNo(ItemTrkgCode);
