+           (FieldNo = FieldNo("Serial No.")) and ("Serial No." <> '') or
+           (FieldNo = FieldNo("Package No.")) and ("Package No." <> '')
+        then
+            ExpDate := ItemTrackingMgt.ExistingExpirationDate(Rec, false, EntriesExist);
+
+        if ExpDate <> 0D then
+            "Expiration Date" := ExpDate;
+    end;
